import{_ as r,o as t,c as a,af as o}from"./chunks/framework.BSym9njW.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"03-infra/index.md","filePath":"en/03-infra/index.md","lastUpdated":1778460716000}'),n={name:"03-infra/index.md"};function i(s,e,l,c,d,h){return t(),a("div",null,[...e[0]||(e[0]=[o('<div align="center"><h1>03-Infra</h1><strong>⚙️ ROCm Operator Optimization &amp; GPU Programming</strong></div><div align="center"><p><em>From AMD AI hardware landscape to HIP operators and performance profiling</em></p><p><a href="/hello-rocm/">Back to Home</a></p></div><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>This module is designed for developers who want to build a systematic understanding of <strong>AMD GPU + ROCm</strong>: from the AI hardware and ROCm software stack panorama, to the PyTorch call chain and GPU architecture, to writing <strong>HIP</strong> operators by hand and combining <strong>rocBLAS / MIOpen</strong> with performance measurement — covering the ROCm software stack, GPU programming, and operator practice with hands-on examples.</p><p>The default lab environment is <strong>Ubuntu 22.04 / 24.04 + ROCm 7.x</strong>, with example devices including <strong>AMD AI+ MAX395 / Radeon 8060S (gfx1151)</strong> and others. Readers can adapt according to their own GPU and ROCm version.</p><h2 id="tutorial-list" tabindex="-1">Tutorial List <a class="header-anchor" href="#tutorial-list" aria-label="Permalink to &quot;Tutorial List&quot;">​</a></h2><h3 id="chapter-1-embracing-the-new-era-of-amd-ai-computing" tabindex="-1">Chapter 1: Embracing the New Era of AMD AI Computing <a class="header-anchor" href="#chapter-1-embracing-the-new-era-of-amd-ai-computing" aria-label="Permalink to &quot;Chapter 1: Embracing the New Era of AMD AI Computing&quot;">​</a></h3><p>  From Ryzen AI (NPU + GPU), Radeon discrete GPUs, to Instinct data center accelerators — an overview of AMD&#39;s AI product line and typical use cases. Explains <strong>ROCm</strong>&#39;s role in the stack and includes hands-on experiments such as ResNet training and Qwen large model inference with <strong>PyTorch</strong>, building an overall picture of &quot;what you can run on AMD.&quot;</p><ul><li><strong>Target Audience</strong>: Developers and students new to AMD AI / ROCm</li><li><strong>Difficulty Level</strong>: ⭐⭐</li><li><strong>Estimated Time</strong>: 2–3 hours</li></ul><p>📖 <a href="/hello-rocm/03-infra/embrace-amd-ai">Read Chapter 1</a></p><hr><h3 id="chapter-2-decoding-ai-accelerators-—-from-software-stack-to-hardware-architecture" tabindex="-1">Chapter 2: Decoding AI Accelerators — From Software Stack to Hardware Architecture <a class="header-anchor" href="#chapter-2-decoding-ai-accelerators-—-from-software-stack-to-hardware-architecture" aria-label="Permalink to &quot;Chapter 2: Decoding AI Accelerators — From Software Stack to Hardware Architecture&quot;">​</a></h3><p>  Use tools like <code>ldd</code> to trace the <strong>PyTorch → HIP → HSA → Driver → GPU</strong> call chain, understand the CPU&#39;s &quot;low latency&quot; vs GPU&#39;s &quot;high throughput&quot; paradigm, and the <strong>SIMT</strong> execution model. Combined with concepts like <strong>CU, LDS, and VRAM bandwidth</strong>, learn to read how AMD GPUs behave under AI workloads.</p><ul><li><strong>Target Audience</strong>: Developers who can already run models and want to understand the underlying stack and hardware</li><li><strong>Difficulty Level</strong>: ⭐⭐⭐</li><li><strong>Estimated Time</strong>: 3–4 hours</li></ul><p>📖 <a href="/hello-rocm/03-infra/decode-ai-accelerator">Read Chapter 2</a></p><hr><h3 id="chapter-3-entering-the-world-of-rocm-programming-—-writing-your-first-hip-operator" tabindex="-1">Chapter 3: Entering the World of ROCm Programming — Writing Your First HIP Operator <a class="header-anchor" href="#chapter-3-entering-the-world-of-rocm-programming-—-writing-your-first-hip-operator" aria-label="Permalink to &quot;Chapter 3: Entering the World of ROCm Programming — Writing Your First HIP Operator&quot;">​</a></h3><p>  Introduces the correspondence between <strong>HIP</strong> and CUDA, Host/Device code structure. From <strong>writing a Kernel</strong> to reproduce Tensor addition, to using <strong><code>hipEvent</code></strong> for timing, and an initial look at <strong>rocBLAS</strong> and <strong>MIOpen</strong> — completing the transition from Python to device-level code.</p><ul><li><strong>Target Audience</strong>: Developers with C++ basics who are ready to write or read custom operators</li><li><strong>Difficulty Level</strong>: ⭐⭐⭐</li><li><strong>Estimated Time</strong>: 2–3 hours</li></ul><p>📖 <a href="/hello-rocm/03-infra/handwrite-rocm-operator">Read Chapter 3</a></p><hr><h3 id="chapter-4-writing-custom-rocm-operators-for-pytorch" tabindex="-1">Chapter 4: Writing Custom ROCm Operators for PyTorch <a class="header-anchor" href="#chapter-4-writing-custom-rocm-operators-for-pytorch" aria-label="Permalink to &quot;Chapter 4: Writing Custom ROCm Operators for PyTorch&quot;">​</a></h3><p>  Starting from PyTorch&#39;s Python call chain, use the <strong>C++ Extension</strong> mechanism to register HIP Kernels as custom operators. Hands-on with <strong>Fused Swish</strong> operator, <strong>Grid-Stride Loop</strong> optimization, <strong>Autograd</strong> integration for automatic differentiation, and <strong>memory-wall benchmarks</strong> to quantify bandwidth bottlenecks — completing the full loop from &quot;hand-written Kernel&quot; to &quot;PyTorch-callable operator.&quot;</p><ul><li><strong>Target Audience</strong>: Developers who want to integrate custom HIP operators into PyTorch training/inference workflows</li><li><strong>Difficulty Level</strong>: ⭐⭐⭐⭐</li><li><strong>Estimated Time</strong>: 3–4 hours</li></ul><p>📖 <a href="/hello-rocm/03-infra/custom-pytorch-operator">Read Chapter 4</a></p><hr><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="hardware-requirements" tabindex="-1">Hardware Requirements <a class="header-anchor" href="#hardware-requirements" aria-label="Permalink to &quot;Hardware Requirements&quot;">​</a></h3><ul><li>AMD GPU (ROCm-supported GPU, such as RX 7000 / 9000 series, Ryzen AI MAX / AI 300, Instinct MI series, etc.)</li><li>VRAM requirements vary by chapter: Chapter 1 involves ResNet / large model inference, so ensure sufficient VRAM; Chapters 3 and 4 focus on small HIP programs and matrix experiments, so a typical consumer GPU will suffice</li></ul><h3 id="software-requirements" tabindex="-1">Software Requirements <a class="header-anchor" href="#software-requirements" aria-label="Permalink to &quot;Software Requirements&quot;">​</a></h3><ul><li>Operating System: Linux (Ubuntu 22.04+; tutorials use 22.04 / 24.04 as examples)</li><li>ROCm 7.10.0 or later (chapters may also reference 7.x; verify with your local <code>rocm-smi</code> / release notes)</li><li>Chapter 1: Python 3.10+, PyTorch (ROCm build)</li><li>Chapters 3 &amp; 4: Recommended to install <strong>ROCm HIP development components</strong> (e.g., <code>hipcc</code>, <code>rocm-dev</code>, etc. — package names may vary by distribution), CMake 3.16+, GCC 9+ or Clang 12+</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>Q: How do I check if my AMD GPU supports ROCm?</summary><p>Please refer to the <a href="https://rocm.docs.amd.com/projects/install-on-linux/en/latest/reference/system-requirements.html" target="_blank" rel="noreferrer">ROCm Official Support List</a> for supported GPU models and distribution combinations.</p></details><details><summary>Q: What is the relationship between Chapters 3 &amp; 4 and Chapters 1 &amp; 2?</summary><p>Chapters 1 &amp; 2 focus on the <strong>big picture and stack/hardware understanding</strong>; Chapters 3 &amp; 4 focus on <strong>HIP programming and operator-level practice</strong>. The chapter titles are closely related: you can read Chapter 3 first to build a minimal end-to-end workflow, then read Chapter 4 for mapping and performance deep-dives; if time is limited, you can also selectively read based on your background.</p></details><details><summary>Q: Getting &quot;header not found&quot; or &quot;linking library not found&quot; errors when compiling HIP programs?</summary><ol><li>Confirm the corresponding ROCm development packages are installed and <code>hipcc</code> is in your <code>PATH</code></li><li>Check that <code>HIP_PATH</code>, <code>ROCM_PATH</code>, and other environment variables match the installation path</li><li>Refer to the <a href="https://rocm.docs.amd.com/projects/HIP/en/latest/" target="_blank" rel="noreferrer">HIP Installation &amp; Getting Started</a> guide to verify dependencies</li></ol></details><h2 id="reference-resources" tabindex="-1">Reference Resources <a class="header-anchor" href="#reference-resources" aria-label="Permalink to &quot;Reference Resources&quot;">​</a></h2><ul><li><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer">ROCm Official Documentation</a></li><li><a href="https://rocm.docs.amd.com/projects/HIP/en/latest/" target="_blank" rel="noreferrer">HIP Programming Guide</a></li><li><a href="https://rocm.docs.amd.com/projects/rocBLAS/en/latest/" target="_blank" rel="noreferrer">rocBLAS Documentation</a></li><li><a href="https://rocm.docs.amd.com/projects/MIOpen/en/latest/" target="_blank" rel="noreferrer">MIOpen Documentation</a></li><li><a href="https://pytorch.org/get-started/locally/" target="_blank" rel="noreferrer">PyTorch for ROCm</a></li></ul><hr><div align="center"><p><strong>Contributions of more operator optimization and GPU programming practice content are welcome!</strong> 🎉</p><p><a href="https://github.com/datawhalechina/hello-rocm/issues" target="_blank" rel="noreferrer">Submit an Issue</a> | <a href="https://github.com/datawhalechina/hello-rocm/pulls" target="_blank" rel="noreferrer">Submit a PR</a></p></div>',39)])])}const u=r(n,[["render",i]]);export{p as __pageData,u as default};
